import {
  SensorSDKName,
  getArgsFromUrl,
  getPlatform,
  initWebSensors,
  reportWebSensors,
} from '@badam/common-utils'
import { Events, reportEvent } from '../event'

export function getMp4url(url: string) {
  const DOMAIN = window.location.hostname
  if (DOMAIN.indexOf('cdn-') === -1) {
    return url.replace('cdn-', '')
  }
  return url
}

// export const isLudo = getArgsFromUrl('package') !== 'cn.sawalive.isawa'
export const pkg = getArgsFromUrl('package')

export const isInLudoClient = getArgsFromUrl('bundle_id') === 'com.sawa.ludo'

