export function getAuthType(pkg: string) {
  if (pkg === 'cn.sawalive.isawa') {
    return 1
  } else if (pkg === 'com.sawa.ludo') {
    return 2
  } else if (pkg === 'com.sawa.ksa') { // 注意，这里和 bind 的不一样
    return 2
  }
  return 1
}

