export function refreshAccount(accountResp: any, source: string) {
  const { identities, user_info } = accountResp.data

  if (user_info) {
    const { session_key, uid, icon_verify } = user_info
    const o = { session_key, uid, icon_verify }
    const v = encodeURIComponent(JSON.stringify(o))
    const host = isInLudoClient ? 'sawaludo' : 'sawaksa'
    window.location.href = `${host}://sawaksa_login/?sawaksa_acount=${v}&source=${source}`
  }
}

export function cancelAccount(key: string) {
  const host = isInLudoClient ? 'sawaludo' : 'sawaksa'
  window.location.href = `${host}://unregister/?cancel_account_key=${key}`
}

export function unregisterRemind(data: any) {
  const host = isInLudoClient ? 'sawaludo' : 'sawaksa'
  window.location.href = `${host}://unregister_remind/?data=${encodeURIComponent(
    JSON.stringify(data)
  )}`
}

export function toFeedback() {
  reportEvent(Events.account_cancellation_verify_page_operation_result, {
    operation: '点击反馈入口',
  })
  const host = isInLudoClient ? 'sawaludo' : 'sawaksa'
  window.location.href = `${host}://feedback`
}

export async function report(eventName: string, fields = {}) {
  if (getPlatform().isIPhone) {
    const json = fields
    const host = isInLudoClient ? 'sawaludo' : 'sawaksa'
    window.location.href = `${host}://sawaksa_login_event/?eventName=${eventName}&jsonData=${btoa(
      encodeURIComponent(JSON.stringify(json))
    )}`
  } else {
    //
    let sa = getArgsFromUrl('sa')
    if (sa) {
      sa = decodeURIComponent(sa)
      const isDebug = getArgsFromUrl('is_debug')
      await initWebSensors(isDebug ? SensorSDKName.TEST : SensorSDKName.KSA, true, 'ajax', sa)
      reportWebSensors(eventName, fields)
    }
  }
}

export function getSub(access_token: string) {
  const arr = access_token.split('.')
  if (arr.length < 3) {
    return ''
  }
  try {
    const obj = arr[1]
    const subs = atob(obj)
    const o = JSON.parse(subs)
    const sub = o.sub
    return sub
  } catch (e) {
    return ''
  }
}
